const today = new Date();
// pageCoffee tourne sur 5 valeurs selon le jour de la semaine (lun=1 … ven=5)
// COFFEE a largement assez de records pour 5 pages × 20 = 100 résultats / semaine
// TORREFACT et BRULERIE restent sur page=1 (peu de records en France)
const dayOfWeek = today.getDay(); // 0=dim, 1=lun … 5=ven, 6=sam
const pageCoffee = (dayOfWeek % 5) + 1; // 1 à 5
return [{ json: { pageCoffee, date: today.toISOString().split('T')[0] } }];

// CIBLES PREMIUM uniquement : specialty coffee shops, torréfacteurs, grands hôtels,
// épiceries fines. On rejette tout ce qui est générique ou bas de gamme.

const BLACKLIST_NOM = [
  'STARBUCKS', 'COLUMBUS', 'MCDONALD', 'CAFETERIA', 'CASINO',
  'MONOPRIX', 'FRANPRIX', 'CARREFOUR', 'LECLERC', 'RELAY',
  'HOPITAL', 'EHPAD', 'WOK', 'SUSHI', 'PIZZA', 'BURGER', 'KEBAB',
  'SUBWAY', 'QUICK', 'KFC', 'FLUNCH', 'COURTEPAILLE', 'HIPPOPOTAMUS',
  'DOMINO', 'FIVE GUYS', 'COJEAN', 'RAMEN', 'PAUL', 'BRIOCHE DOREE',
  'SODEXO', 'ELIOR', 'COMPASS', 'CANTINE', 'RESTAU U', 'INTERMARCHE',
  'LIDL', 'ALDI', 'AUCHAN', 'SUPER U', 'BIOCOOP'
];

// Activités acceptées : établissements susceptibles de valoriser 30€/kg
const WHITELIST_ACTIVITE = [
  'torréfact', 'torrefact',        // torréfacteurs → café vert
  'brûlerie', 'brulerie',          // brûleries → café vert ou torréfié
  'coffee',                         // specialty coffee shops
  'barista', 'espresso', 'specialty',
  'salon de thé', 'tea room', 'tea',
  'épicerie fine', 'epicerie fine', 'épicerie de luxe',
  'gastronomie', 'gastronomique',
  'traiteur de luxe', 'traiteur haut',
  'hôtel', 'hotel', 'palace'
];

// Activités à rejeter explicitement même si le nom passe le filtre
const BLACKLIST_ACTIVITE = [
  'restauration rapide', 'fast food', 'sandwicherie',
  'distribution automatique', 'vending',
  'kebab', 'pizza', 'burger', 'friterie',
  'collectivité', 'scolaire', 'entreprise'
];

const all = $input.all();
const seen = new Set();
const result = [];

for (const item of all) {
  const records = item.json?.data || item.json?.results || [];

  for (const r of records) {
    const name     = (r.APP_Libelle_etablissement || '').trim();
    const activite = (r.APP_Libelle_activite_etablissement || '').toLowerCase();
    const adresse  = (r.Adresse_2_UA || r.Adresse_etablissement || '').trim();
    const cp       = (r.Code_postal || '').toString().trim();
    const commune  = (r.Libelle_commune || '').trim();
    const siret    = (r.SIRET || '').toString().trim();
    const dep      = (r.dep_code || '').toString().trim();
    const note     = (r.Synthese_eval_sanit || '');

    // Île-de-France : 75 77 78 91 92 93 94 95
    const IDF = ['75','77','78','91','92','93','94','95'];
    if (!name || name.length < 3) continue;
    if (cp && !IDF.some(p => cp.startsWith(p))) continue;
    if (note === 'A améliorer') continue;

    const nameUp = name.toUpperCase();
    if (BLACKLIST_NOM.some(b => nameUp.includes(b))) continue;
    if (BLACKLIST_ACTIVITE.some(b => activite.includes(b))) continue;

    const activiteOK = WHITELIST_ACTIVITE.some(w => activite.includes(w));
    if (!activiteOK) continue;

    const key = nameUp.replace(/[^A-Z0-9]/g, '').substring(0, 10);
    if (seen.has(key)) continue;
    seen.add(key);

    // Catégorise pour adapter l'angle du mail et le score Notion
    let typeProspect = 'COFFEE SHOP';
    let score = 8;
    if (activite.includes('torréfact') || activite.includes('torrefact') || activite.includes('brûlerie') || activite.includes('brulerie')) {
      typeProspect = 'TORRÉFACTEUR'; score = 9;
    } else if (activite.includes('hôtel') || activite.includes('hotel') || activite.includes('palace')) {
      typeProspect = 'HÔTEL'; score = 9;
    } else if (activite.includes('épicerie fine') || activite.includes('epicerie fine') || activite.includes('gastronomie') || activite.includes('traiteur')) {
      typeProspect = 'ÉPICERIE FINE'; score = 8;
    } else if (activite.includes('salon de thé') || activite.includes('tea')) {
      typeProspect = 'SALON DE THÉ'; score = 7;
    }

    result.push({ nom: name, adresse, code_postal: cp, commune, activite: r.APP_Libelle_activite_etablissement || '', siret, dep, key, typeProspect, score });
  }
}

console.log('Résultats après filtre premium:', result.length);

if (result.length === 0) {
  return [{ json: { _skip: true } }];
}

// Trie par score décroissant pour prioriser torréfacteurs et hôtels
result.sort((a, b) => b.score - a.score);

return result.slice(0, 15).map(r => ({ json: r }));

const allItems = $input.all();
const candidats   = allItems.filter(i => i.json.key);
const notionItems = allItems.filter(i => !i.json.key);

const existing = new Set();
for (const item of notionItems) {
  const results = item.json?.results || [];
  for (const r of results) {
    const t = r.properties?.Nom?.title?.[0]?.plain_text || '';
    if (t) existing.add(t.toUpperCase().replace(/[^A-Z0-9]/g, '').substring(0, 10));
  }
}

const seen = new Set();
const nouveaux = [];
for (const item of candidats) {
  const k = item.json.key;
  if (!existing.has(k) && !seen.has(k)) {
    seen.add(k);
    nouveaux.push({ json: item.json });
  }
}

console.log('Nouveaux prospects premium:', nouveaux.length);

if (nouveaux.length === 0) {
  return [{ json: { _skip: true } }];
}

return nouveaux.slice(0, 8);

const prospect = $('Anti-doublons').item.json;

const jinaRaw = $json;
let rawText = '';

if (typeof jinaRaw === 'string') {
  rawText = jinaRaw;
} else if (jinaRaw?.body) {
  rawText = typeof jinaRaw.body === 'string' ? jinaRaw.body : JSON.stringify(jinaRaw.body);
} else {
  rawText = JSON.stringify(jinaRaw);
}

let webContext = rawText
  .replace(/<[^>]+>/g, ' ')
  .replace(/https?:\/\/[^\s]+/g, '')
  .replace(/\[.*?\]\(.*?\)/g, '')
  .replace(/#{1,6}\s/g, '')
  .replace(/[\r\n]+/g, ' ')
  .replace(/\s{2,}/g, ' ')
  .replace(/"/g, "'")
  .trim()
  .substring(0, 1200);

if (!webContext || webContext.length < 30) {
  webContext = `${prospect.typeProspect} ${prospect.nom} à ${prospect.commune}. Activité : ${prospect.activite}. Pas d'info web disponible.`;
}

return [{ json: { ...prospect, webContext } }];

const aiResponse = $('OpenRouter — Mistral').item.json;
const text = aiResponse?.choices?.[0]?.message?.content || '';

const lines = text.split('\n').map(l => l.trim()).filter(Boolean);
let objet = '';
const bodyLines = [];
let headerParsed = false;

for (const line of lines) {
  if (!headerParsed && /^objet\s*:/i.test(line)) {
    objet = line.replace(/^objet\s*:\s*/i, '').trim();
    headerParsed = true;
  } else if (headerParsed) {
    bodyLines.push(line);
  }
}

if (!objet) {
  objet = 'Un arabica éthiopien pour votre sélection';
  bodyLines.push(...lines);
}

const p = $('Extraire contexte').item.json;
const adresseComplete = [p.adresse || '', p.code_postal || '', p.commune || ''].filter(Boolean).join(', ').substring(0, 200);
const notes = [p.siret ? 'SIRET: ' + p.siret : '', p.activite || '', p.typeProspect || ''].filter(Boolean).join(' | ').substring(0, 200);

const notionBody = {
  parent: { database_id: '8aa6d741-7872-47d0-94b9-6ac4bc8039f6' },
  properties: {
    'Nom': {
      title: [{ text: { content: (p.nom || '').substring(0, 100) } }]
    },
    'Adresse': {
      rich_text: [{ text: { content: adresseComplete } }]
    },
    'Catégorie': {
      select: { name: p.typeProspect || 'COFFEE SHOP' }
    },
    'Statut Email': {
      select: { name: 'À envoyer' }
    },
    'Notes': {
      rich_text: [{ text: { content: notes } }]
    }
  },
  children: [
    {
      object: 'block',
      type: 'callout',
      callout: {
        rich_text: [{ type: 'text', text: { content: ('Objet : ' + objet).substring(0, 200) } }],
        icon: { emoji: '📧' },
        color: 'blue_background'
      }
    },
    {
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: [{ type: 'text', text: { content: bodyLines.join('\n').substring(0, 2000) } }]
      }
    },
    {
      object: 'block',
      type: 'divider',
      divider: {}
    },
    {
      object: 'block',
      type: 'callout',
      callout: {
        rich_text: [{ type: 'text', text: { content: ('Contexte web : ' + (p.webContext || 'N/A')).substring(0, 400) } }],
        icon: { emoji: '🌐' },
        color: 'gray_background'
      }
    }
  ]
};

return [{ json: { notionBody } }];
